// src/pages/RegisterManageSub2Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../Dashboard.css';
import './FormPage.css';

function FarmListPage() {
  const [farms, setFarms] = useState([]);
  const [filter, setFilter] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  // Define columns and their initial visibility
  const initialColumns = {
    tenCoSo: { label: 'Tên cơ sở', visible: true },
    tinhThanhPho: { label: 'Tỉnh (TP)', visible: true },
    xaPhuong: { label: 'Xã (Phường)', visible: true },
    diaChiCoSo: { label: 'Địa chỉ cơ sở', visible: true },
    tenNguoiDaiDien: { label: 'Người đại diện', visible: true },
    soDienThoaiNguoiDaiDien: { label: 'SĐT Người đại diện', visible: true },
    emailNguoiDaiDien: { label: 'Email Người đại diện', visible: true },
    loaiHinhCoSo: { label: 'Loại hình cơ sở', visible: true },
    ngayThanhLap: { label: 'Ngày thành lập', visible: true },
    giayPhepKinhDoanh: { label: 'Số GPKD', visible: true },
    // Add other columns here if needed
    mucDichNuoi: { label: 'Mục đích nuôi', visible: false },
    hinhThucNuoi: { label: 'Hình thức nuôi', visible: false },
    maSoCoSoGayNuoi: { label: 'Mã số CS gây nuôi', visible: false },
    tenCoSoKinhDoanhGo: { label: 'Tên CS KD gỗ', visible: false },
    maSoCoSoKinhDoanhGo: { label: 'Mã số CS KD gỗ', visible: false },
    loaiHinhKinhDoanhGo: { label: 'Loại hình KD gỗ', visible: false },
    giayPhepKinhDoanhGo: { label: 'Số GPKD gỗ', visible: false },
  };

  const [columns, setColumns] = useState(initialColumns);
  const [showColumnOptions, setShowColumnOptions] = useState(false); // State to toggle column options visibility

  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(response.data);
      } catch (error) {
        console.error('❌ Lỗi khi lấy danh sách cơ sở nuôi:', error);
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Không thể tải danh sách cơ sở nuôi. Vui lòng thử lại hoặc kiểm tra quyền truy cập.');
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
      }
    };

    if (token) {
      fetchFarms();
    } else {
      navigate('/'); // Chuyển hướng nếu không có token
    }
  }, [token, navigate]);

  const handleDelete = async (id) => {
    // Thay thế window.confirm bằng một modal xác nhận tùy chỉnh
    if (window.confirm('Bạn có chắc chắn muốn xoá?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(farms.filter(f => f._id !== id));
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Xoá thành công!');
      } catch (error) {
        console.error('Lỗi khi xoá:', error);
        // Thay thế alert bằng một thông báo trên UI hoặc modal
        // alert('Xoá thất bại. Vui lòng thử lại hoặc kiểm tra quyền truy cập.');
      }
    }
  };

  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Chuyển hướng đến trang chỉnh sửa
  };

  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Chuyển hướng đến trang chi tiết farm
  };

  // Cập nhật logic lọc để bao gồm các trường mới nếu cần
  const filteredFarms = farms.filter(f =>
    (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase())
  );

  // Handle column visibility change
  const handleColumnToggle = (columnKey) => {
    setColumns(prevColumns => ({
      ...prevColumns,
      [columnKey]: {
        ...prevColumns[columnKey],
        visible: !prevColumns[columnKey].visible
      }
    }));
  };

  // Get visible column keys for rendering
  const visibleColumnKeys = Object.keys(columns).filter(key => columns[key].visible);

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <div style={{ marginBottom: 20, display: 'flex', alignItems: 'center', gap: 10 }}>
        <input
          type="text"
          placeholder="🔍 Tìm kiếm theo tỉnh, tên cơ sở, người đại diện, hoặc địa chỉ..."
          value={filter}
          onChange={e => setFilter(e.target.value)}
          style={{ padding: 8, flexGrow: 1 }}
        />
        <button
          onClick={() => setShowColumnOptions(!showColumnOptions)}
          style={{
            padding: '8px 15px',
            backgroundColor: '#3498db',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer',
            transition: 'background-color 0.2s ease'
          }}
        >
          {showColumnOptions ? 'Ẩn Tùy chọn Cột' : 'Hiện Tùy chọn Cột'}
        </button>
      </div>

      {showColumnOptions && (
        <div style={{ marginBottom: 20, padding: 15, border: '1px solid #ddd', borderRadius: '8px', backgroundColor: '#f9f9f9' }}>
          <h3>Chọn cột hiển thị:</h3>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 15 }}>
            {Object.keys(columns).map(key => (
              <label key={key} style={{ display: 'flex', alignItems: 'center', cursor: 'pointer' }}>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  onChange={() => handleColumnToggle(key)}
                  style={{ marginRight: 8 }}
                />
                {columns[key].label}
              </label>
            ))}
          </div>
        </div>
      )}

      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              {visibleColumnKeys.map(key => (
                <th key={key}>{columns[key].label}</th>
              ))}
              <th>🛠️</th> {/* Action column always visible */}
            </tr>
          </thead>
          <tbody>
            {filteredFarms.map((f, i) => (
              <tr key={f._id || i}>
                {visibleColumnKeys.map(key => (
                  <td key={key}>
                    {key === 'ngayThanhLap' ? (f[key] ? new Date(f[key]).toLocaleDateString() : '') : f[key]}
                  </td>
                ))}
                <td>
                  <button onClick={() => handleView(f._id)} className="action-button view-button">Sổ nuôi</button>{' '}
                  <button onClick={() => handleEdit(f._id)} className="action-button edit-button">✏️</button>{' '}
                  <button onClick={() => handleDelete(f._id)} className="action-button delete-button">🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default FarmListPage;
